import "server-only";

import { Unkey } from "@unkey/api";

function requireEnv(key: string) {
  const value = process.env[key];
  if (!value) throw new Error(`${key} is required.`);
  return value;
}

export const unkey = new Unkey({ rootKey: requireEnv("UNKEY_ROOT_KEY") });

import { unkey } from "./client";

function requireEnv(key: string) {
  const value = process.env[key];
  if (!value) throw new Error(`${key} is required.`);
  return value;
}

export async function createUnkeyApiKey(ownerId: string) {
  return unkey.keys.create({
    apiId: requireEnv("UNKEY_API_ID"),
    externalId: ownerId,
    prefix: "sf",
  });
}

export async function verifyUnkeyApiKey(key: string) {
  return unkey.keys.verifyKey({ key });
}

import { NextResponse } from "next/server";

import { verifyUnkeyApiKey } from "@/lib/unkey/api-keys";

export async function POST(request: Request) {
  let body: { key?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  if (!body.key) return NextResponse.json({ error: "key is required" }, { status: 400 });

  const result = await verifyUnkeyApiKey(body.key);
  return NextResponse.json(result);
}

const deployChecks = [
  "Create the provider project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function UnkeyAPIKeysPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Unkey API Keys</h1>
        <p className="text-muted-foreground">Managed API key lifecycle and verification for developer platforms.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
